const _ = require('lodash');
const problemsData = require('../../data/problems.json');

/**
 * Fetch problems with optional filters: difficulty, limit, and skill tags.
 * Skill tags filter is case-insensitive and supports comma-separated string or array input.
 * Returns problems sorted by stable criteria (e.g., id ascending).
 * Also returns metadata including normalized skill tags filter.
 *
 * @param {Object} options
 * @param {string|Array<string>} [options.skillTags] - Skill tags filter (case-insensitive)
 * @param {string} [options.difficulty] - Difficulty filter
 * @param {number} [options.limit] - Limit number of problems returned
 * @returns {Object} { problems: Array, metadata: Object }
 */
function getProblems({ skillTags, difficulty, limit } = {}) {
  let tagsFilter = [];

  if (skillTags) {
    if (typeof skillTags === 'string') {
      tagsFilter = skillTags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
    } else if (Array.isArray(skillTags)) {
      tagsFilter = skillTags.map(t => String(t).toLowerCase().trim()).filter(t => t.length > 0);
    }
  }

  // Filter problems
  let filtered = problemsData;

  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  if (tagsFilter.length > 0) {
    filtered = filtered.filter(p => {
      if (!p.tags || !Array.isArray(p.tags)) return false;
      const problemTagsLower = p.tags.map(t => t.toLowerCase());
      // All tagsFilter must be present in problem tags
      return tagsFilter.every(tag => problemTagsLower.includes(tag));
    });
  }

  // Stable sort by id ascending
  filtered = _.sortBy(filtered, ['id']);

  if (limit && Number.isInteger(limit) && limit > 0) {
    filtered = filtered.slice(0, limit);
  }

  return {
    problems: filtered,
    metadata: {
      skillTags: tagsFilter
    }
  };
}

module.exports = {
  getProblems
};
